import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Safety/cloudflare-api-token.md","filePath":"fa/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"fa/Safety/cloudflare-api-token.md"};function c(n,e,p,s,u,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials به ImgBed اجازه می‌دهد پس از تغییر files، Cloudflare CDN cache را purge کند.</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>admin panel را باز کنید و بروید به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>باید این موارد را پر کنید:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="این-setting-چه-می‌کند" tabindex="-1">این Setting چه می‌کند <a class="header-anchor" href="#این-setting-چه-می‌کند" aria-label="Permalink to &quot;این Setting چه می‌کند&quot;">​</a></h2><p>Cloudflare ممکن است public image URLs را cache کند.</p><p>Caching باعث سریع‌تر شدن delivery تصویر می‌شود، اما بعد از delete، block، replace یا move کردن file ممکن است content قدیمی مدتی دیده شود.</p><p>بعد از configure شدن Cloudflare API credentials، ImgBed پس از پایان این operations تلاش می‌کند cache مربوط به Cloudflare را purge کند.</p><p>این حالت مفید است وقتی:</p><ul><li>image را delete می‌کنید و می‌خواهید public link هرچه زودتر از کار بیفتد.</li><li>image را block می‌کنید و می‌خواهید visitors دیگر original file را نبینند.</li><li>file را با همان نام replace می‌کنید و می‌خواهید visitors نسخه جدید را زودتر ببینند.</li><li>files را move یا rename می‌کنید و می‌خواهید old path cache سریع refresh شود.</li><li>public access rules را تغییر می‌دهید و می‌خواهید public gallery یا random image cache زودتر update شود.</li></ul><h2 id="اگر-خالی-بماند-چه-می‌شود" tabindex="-1">اگر خالی بماند چه می‌شود <a class="header-anchor" href="#اگر-خالی-بماند-چه-می‌شود" aria-label="Permalink to &quot;اگر خالی بماند چه می‌شود&quot;">​</a></h2><p>ImgBed بدون این setting هم عادی کار می‌کند.</p><p>تنها تفاوت این است که ImgBed به‌صورت فعال Cloudflare CDN cache را purge نمی‌کند. visitors ممکن است تا زمان expire شدن طبیعی Cloudflare cache، content قدیمی را ببینند.</p><h2 id="پیدا-کردن-zone-id" tabindex="-1">پیدا کردن Zone ID <a class="header-anchor" href="#پیدا-کردن-zone-id" aria-label="Permalink to &quot;پیدا کردن Zone ID&quot;">​</a></h2><p>Zone ID همان Cloudflare Zone ID مربوط به سایتی است که ImgBed domain شما روی آن قرار دارد.</p><ol><li>وارد Cloudflare dashboard شوید.</li><li>سایتی را باز کنید که ImgBed domain داخل آن است.</li><li>در site overview page، <code>Zone ID</code> را پیدا کنید.</li><li>آن را در field <code>Zone ID</code> داخل ImgBed copy کنید.</li></ol><p>این site Zone ID است، نه account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>email addressی را وارد کنید که با آن وارد Cloudflare می‌شوید.</p><p>باید با API Key پایین هماهنگ باشد.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Cloudflare Global API Key خود را وارد کنید.</p><ol><li>وارد Cloudflare dashboard شوید.</li><li>profile خود را باز کنید.</li><li>به API Tokens page بروید.</li><li><code>Global API Key</code> را پیدا کنید.</li><li>آن را view و copy کنید.</li><li>داخل field <code>API Key</code> در ImgBed paste کنید.</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="چه-زمانی-اثر-می‌کند" tabindex="-1">چه زمانی اثر می‌کند <a class="header-anchor" href="#چه-زمانی-اثر-می‌کند" aria-label="Permalink to &quot;چه زمانی اثر می‌کند&quot;">​</a></h2><p>پس از پر کردن fields، settings را save کنید.</p><p>file changes آینده به‌صورت خودکار تلاش می‌کنند Cloudflare cache را purge کنند. operations قبلی retroactively purge نمی‌شوند. اگر پیش از setup، file را delete یا replace کرده‌اید، باید منتظر expire شدن Cloudflare cache بمانید یا آن را در Cloudflare دستی purge کنید.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="آیا-required-است؟" tabindex="-1">آیا Required است؟ <a class="header-anchor" href="#آیا-required-است؟" aria-label="Permalink to &quot;آیا Required است؟&quot;">​</a></h3><p>خیر.</p><p>اگر domain شما از Cloudflare استفاده نمی‌کند، یا CDN cache delay برایتان مهم نیست، می‌توانید آن را خالی بگذارید.</p><h3 id="credentials-اشتباه-upload-را-خراب-می‌کند؟" tabindex="-1">credentials اشتباه upload را خراب می‌کند؟ <a class="header-anchor" href="#credentials-اشتباه-upload-را-خراب-می‌کند؟" aria-label="Permalink to &quot;credentials اشتباه upload را خراب می‌کند؟&quot;">​</a></h3><p>معمولاً خیر.</p><p>credentials اشتباه فقط جلوی purge کردن Cloudflare cache توسط ImgBed را می‌گیرد. upload و normal file access باید ادامه پیدا کند.</p><h3 id="چرا-deleted-image-هنوز-باز-می‌شود؟" tabindex="-1">چرا deleted image هنوز باز می‌شود؟ <a class="header-anchor" href="#چرا-deleted-image-هنوز-باز-می‌شود؟" aria-label="Permalink to &quot;چرا deleted image هنوز باز می‌شود؟&quot;">​</a></h3><p>رایج‌ترین دلیل این است که Cloudflare هنوز file قدیمی را cache کرده است.</p><p>با Cloudflare API credentials درست، ImgBed هنگام delete شدن file cache مربوط به URL را purge می‌کند.</p><h3 id="چرا-پس-از-replace-کردن-file-هنوز-تصویر-قدیمی-را-می‌بینم؟" tabindex="-1">چرا پس از replace کردن file هنوز تصویر قدیمی را می‌بینم؟ <a class="header-anchor" href="#چرا-پس-از-replace-کردن-file-هنوز-تصویر-قدیمی-را-می‌بینم؟" aria-label="Permalink to &quot;چرا پس از replace کردن file هنوز تصویر قدیمی را می‌بینم؟&quot;">​</a></h3><p>این هم معمولاً به CDN cache مربوط است.</p><p>بعد از configure شدن این setting، ImgBed هنگام overwrite شدن file با همان نام تلاش می‌کند old URL cache را purge کند.</p>',44)])])}const I=i(d,[["render",c]]);export{b as __pageData,I as default};
